+#[serde(rename_all = "snake_case")]
+pub enum RateLimitWindow {
+    /// Per-session/run limit.
+    Run,
+    /// Per-minute limit.
+    Minute,
+    /// Per-hour limit.
+    Hour,
+    /// Per-day limit.
+    Day,
