+    let result = checker.check_candidate(&large_candidate);
+    assert!(!result.allowed, "Large process should be blocked");
+    assert!(result
+        .violations
+        .iter()
+        .any(|v| v.constraint == ConstraintKind::MaxBlastRadius));
