+        let mut high = 0.99;
+
+        // Get classifications at extremes
+        let low_evidence = Evidence {
+            cpu: Some(CpuEvidence::Fraction { occupancy: low }),
+            ..Evidence::default()
+        };
+        let low_result = compute_posterior(&priors, &low_evidence).expect("low");
