+            let mid_result = compute_posterior(&priors, &mid_evidence).expect("mid");
+            let mid_class = get_classification(&mid_result.posterior);
+
+            if mid_class == low_class {
+                low = mid;
+            } else {
+                high = mid;
+            }
+        }
+
+        let threshold = (low + high) / 2.0;
+        assert!(
